// Generated by Skyramp v1.3.25 — per-file upload progress list test
// Tests the changed behavior in app/src/components/v-upload.vue:
//   - Per-file rows with data-testid="upload-file-row" and data-state attribute
//   - Per-file progress bars with data-testid="upload-file-progress"
//   - Cancel All button with data-testid="upload-cancel-all"
//   - Aggregate progress bar with data-testid="upload-aggregate-progress"

import { test, expect, newSkyrampPlaywrightPage } from '@skyramp/skyramp';

const pageTimeout = 15000;

test('testUi', async ({ page }) => {
    test.setTimeout(598000);

    const errors: Error[] = [];
    page.on('pageerror', (err) => errors.push(err));

    page.setDefaultTimeout(pageTimeout);
    page = newSkyrampPlaywrightPage(page);

    await page.goto("http://localhost:8055");
    await page.waitForTimeout(3000);

    await page.getByRole("textbox", { name: "Email" }).fill("admin@example.com");
    await page.getByRole("textbox", { name: "Password" }).fill("admin");
    const loginResponsePromise = page.waitForResponse("**/auth/login**");
    await page.getByRole("button", { name: "Sign In" }).click();
    const loginResponse = await loginResponsePromise;
    expect(loginResponse.status()).toBe(200);

    await page.waitForTimeout(3000);
    await page.goto("http://localhost:8055/admin/files/+");
    await page.waitForTimeout(3000);
    await page.waitForLoadState('networkidle');

    await expect(page).toHaveURL(/admin\/files\/\+/);
    await expect(page.getByRole("button", { name: "Choose File file_upload" })).toBeVisible();

    // Trigger multi-file upload by setting two files on the hidden file input
    const fileInput = page.locator('input[type="file"]');
    await fileInput.setInputFiles([
        { name: 'test-document.txt', mimeType: 'text/plain', buffer: Buffer.from('test document content') },
        { name: 'test-image.txt', mimeType: 'text/plain', buffer: Buffer.from('test image content') }
    ]);

    // Wait for Vue reactivity to update the DOM
    await page.locator('[data-testid="upload-file-row"]').first().waitFor({ state: 'visible', timeout: 10000 });

    // Per-file list must appear when multiple files are selected
    await expect(page.getByTestId("upload-file-row")).toHaveCount(2);
    await expect(page.getByTestId("upload-file-row").nth(0)).toHaveAttribute("data-file-name", "test-document.txt");
    await expect(page.getByTestId("upload-file-row").nth(1)).toHaveAttribute("data-file-name", "test-image.txt");

    // Cancel All button must be visible during multi-file upload
    await expect(page.getByTestId("upload-cancel-all")).toBeVisible();
    await expect(page.getByTestId("upload-cancel-all")).toHaveText("Cancel all");

    // Aggregate progress bar must carry the new data-testid attribute
    await expect(page.getByTestId("upload-aggregate-progress")).toBeVisible();

    // Per-file progress bars must appear for files not yet done
    await expect(page.getByTestId("upload-file-progress")).toHaveCount(2);

    expect(errors).toHaveLength(0);
});
